import javax.jws.WebMethod;
import javax.jws.WebParam;
import javax.jws.WebService;
import java.util.List;

@WebService(targetNamespace = "http://example.com/ecommerce")
public class OrderProcessingService {

    @WebMethod(operationName = "processOrder")
    public double processOrder(@WebParam(name = "items") List<Item> items) {
        double totalPrice = 0.0;

        for (Item item : items) {
            totalPrice += item.getPrice() * item.getQuantity();
        }

        // Process the order here (e.g., save to database, send confirmation email)

        return totalPrice;
    }
}

